// A closure is a function's ability to remember and access variables from its surrounding scope, even after that outer function has finished executing.
// The inner function "closes over" the outer function's variables.
function outerFunction(outerVar) {
  let innerVar = "Inner";

  function innerFunction() {
    console.log("Outer variable: " + outerVar);
    console.log("Inner variable: " + innerVar);
  }

  return innerFunction;
}

let myClosure = outerFunction("Outer Value");
myClosure(); // Output: Outer variable: Outer Value, Inner variable: Inner
```

